from typing import List


class Solution:
    def longestValidSkillChain(self, type: List[int]) -> int:
        n = len(type)
        if n == 0:
            return 0

        dp0 = dp1 = dp2 = 0
        ans = 0

        for i in range(n):
            nd0 = nd1 = nd2 = 0
            if type[i] == 0:
                nd0 = 1
                if i > 0:
                    # 基础类型可接在 0/1/2 之后，或单独作为新链起点
                    nd0 = max(nd0, dp0 + 1, dp1 + 1, dp2 + 1)
            elif type[i] == 1:
                # 扩展类型：直接前驱必须是基础类型
                if i > 0 and type[i - 1] == 0 and dp0 > 0:
                    nd1 = dp0 + 1
            elif type[i] == 2:
                # 高级类型：前驱与前前驱都必须是 0
                if i >= 2 and type[i - 1] == 0 and type[i - 2] == 0 and dp0 > 0:
                    nd2 = dp0 + 1

            dp0, dp1, dp2 = nd0, nd1, nd2
            ans = max(ans, dp0, dp1, dp2)

        return ans
```

```java
public class Solution {
    public int longestValidSkillChain(int[] type) {
        int n = type.length;
        if (n == 0) return 0;

        int dp0 = 0, dp1 = 0, dp2 = 0, ans = 0;
        for (int i = 0; i < n; i++) {
            int nd0 = 0, nd1 = 0, nd2 = 0;
            if (type[i] == 0) {
                nd0 = 1;
                if (i > 0) {
                    nd0 = Math.max(nd0, Math.max(dp0 + 1, Math.max(dp1 + 1, dp2 + 1)));
                }
            } else if (type[i] == 1) {
                if (i > 0 && type[i - 1] == 0 && dp0 > 0) {
                    nd1 = dp0 + 1;
                }
            } else if (type[i] == 2) {
                if (i >= 2 && type[i - 1] == 0 && type[i - 2] == 0 && dp0 > 0) {
                    nd2 = dp0 + 1;
                }
            }
            dp0 = nd0;
            dp1 = nd1;
            dp2 = nd2;
            ans = Math.max(ans, Math.max(dp0, Math.max(dp1, dp2)));
        }
        return ans;
    }
}
