int longestValidSkillChain(int* type, int typeSize) {
    if (typeSize == 0) return 0;

    int dp0 = 0, dp1 = 0, dp2 = 0, ans = 0;
    for (int i = 0; i < typeSize; i++) {
        int nd0 = 0, nd1 = 0, nd2 = 0;
        if (type[i] == 0) {
            nd0 = 1;
            // 基础类型可接在 0/1/2 之后，或单独作为新链起点
            if (i > 0) {
                if (dp0 + 1 > nd0) nd0 = dp0 + 1;
                if (dp1 + 1 > nd0) nd0 = dp1 + 1;
                if (dp2 + 1 > nd0) nd0 = dp2 + 1;
            }
        } else if (type[i] == 1) {
            // 扩展类型：直接前驱必须是基础类型
            if (i > 0 && type[i - 1] == 0 && dp0 > 0) {
                nd1 = dp0 + 1;
            }
        } else if (type[i] == 2) {
            // 高级类型：前驱与前前驱都必须是 0
            if (i >= 2 && type[i - 1] == 0 && type[i - 2] == 0 && dp0 > 0) {
                nd2 = dp0 + 1;
            }
        }
        dp0 = nd0;
        dp1 = nd1;
        dp2 = nd2;
        if (dp0 > ans) ans = dp0;
        if (dp1 > ans) ans = dp1;
        if (dp2 > ans) ans = dp2;
    }
    return ans;
}
